properties.script:
//Use fully qualified names to avoid resolution issues across different Mirth versions
var channelController = com.mirth.connect.server.controllers.ChannelController.getInstance();
var configController = com.mirth.connect.server.controllers.ConfigurationController.getInstance();
var serializer = com.mirth.connect.model.converters.ObjectXMLSerializer.getInstance();

//Fetch all channels and metadata from the server database
var allChannels = channelController.getChannels(null);
var allMetadata = configController.getChannelMetadata();

//Initialize a Java ArrayList
var resultList = new java.util.ArrayList();

if (allChannels != null)
{
for (var i = 0; i < allChannels.size(); i++)
{
var channel = allChannels.get(i);
var channelId = channel.getId();

// Serialize the channel object to XML string
var channelXml = serializer.serialize(channel);
var metadata = allMetadata.get(channelId);
var metadataXml = "";

if (metadata != null)
{
    var rawMeta = serializer.serialize(metadata);

    //1. Force to a JavaScript String to ensure we use JS replace()
    var metaString = String(rawMeta); 

    //2. Perform the replacement
    var cleanMeta = metaString
        .replace("<com.mirth.connect.model.ChannelMetadata>", "<metadata>")
        .replace("</com.mirth.connect.model.ChannelMetadata>", "</metadata>");

    metadataXml = "\n  <exportData>\n    " + cleanMeta + "\n  </exportData>";
}

//Inject metadata before the closing channel tag
var finalXml = channelXml.toString().replace('</channel>', metadataXml + "\n</channel>");

//Add the XML string to the list for processing
resultList.add(finalXml);
}
}

return resultList;

com.mirth.connect.plugins.javascriptstep.script:
var raw = String(connectorMessage.getRawData());

//Extract name from <name> tag
var nameStart = raw.indexOf("<name>") + 6;
var nameEnd = raw.indexOf("</name>");
var channelName = raw.substring(nameStart, nameEnd);

channelMap.put('backupFilename', channelName + ".xml");

//Use the clean XML from the source
tmp = raw;

channel.postprocessingScript:
var rootBackupDir = "CHANGEPOSTPROCESSINGPATH"; //Enter the base path, NOT the date folder
var daysToKeep = 7;
var millisecondsInDay = 24 * 60 * 60 * 1000;
var retentionPeriod = daysToKeep * millisecondsInDay;
var currentTime = new java.util.Date().getTime();

try 
{
    var parentDir = new java.io.File(rootBackupDir);

    if (parentDir.exists() && parentDir.isDirectory()) 
    {
        var folders = parentDir.listFiles();

        for (var i = 0; i < folders.length; i++) 
        {
            var folder = folders[i];
            var folderName = folder.getName();

            //Check if it is a directory AND contains "Backup 20"
            if (folder.isDirectory() && folderName.indexOf("Backup 20") !== -1) 
            {
                var diff = currentTime - folder.lastModified();

                if (diff > retentionPeriod) 
                {
                    //This helper function deletes a folder and all its contents
                    if (deleteFolder(folder)) 
                    {
                        logger.info("Deleted expired backup folder: " + folderName);
                    } 
                    else 
                    {
                        logger.error("Failed to delete folder: " + folderName);
                    }
                }
            }
        }
    }
} 
catch (e) 
{
    logger.error("Error during folder cleanup: " + e.toString());
}

//Helper function to handle non-empty directories
function deleteFolder(folder) 
{
    var files = folder.listFiles();
    if (files != null) 
    {
        for (var j = 0; j < files.length; j++) 
        {
            deleteFolder(files[j]);
        }
    }
    return folder.delete();
}

channel.deployScript:
// This script executes once when the channel is deployed
